"use client";

import React, { useState, useRef, useCallback } from 'react';
import { cn } from "@/lib/utils";

export interface AuroraInputProps extends Omit<React.InputHTMLAttributes<HTMLInputElement>, 'size'> {
  label?: string;
  helperText?: string;
  error?: string;
  inputSize?: 'sm' | 'md' | 'lg';
  icon?: React.ReactNode;
    className?: string;
}

export const AuroraInput = React.forwardRef<any, AuroraTextareaProps>(({ label, helperText, error, inputSize = 'md', icon, className = '', ...rest }, ref) => {
        const [isFocused, setIsFocused] = useState(false);
        const [mousePos, setMousePos] = useState({ x: 50, y: 50 });
        const wrapperRef = useRef<HTMLDivElement>(null);

        const handleMouseMove = useCallback((e: React.MouseEvent) => {
        if (!wrapperRef.current) return;
        const rect = wrapperRef.current.getBoundingClientRect();
        setMousePos({
          x: ((e.clientX - rect.left) / rect.width) * 100,
          y: ((e.clientY - rect.top) / rect.height) * 100,
        });
        }, []);

        const sizeClasses = {
        sm: 'aurora-input-sm',
        md: 'aurora-input-md',
        lg: 'aurora-input-lg',
        };

        const hasError = !!error;

        return (
        <div ref={ref} {...props} className={cn("aurora-input-group", className)}>
          {label && (
            <label className="aurora-label">{label}</label>
          )}

          <div
            ref={wrapperRef}
            className={`aurora-input-wrapper ${isFocused ? 'focused' : ''} ${hasError ? 'error' : ''}`}
            onMouseMove={handleMouseMove}
            style={{
              '--mouse-x': `${mousePos.x}%`,
              '--mouse-y': `${mousePos.y}%`,
            } as React.CSSProperties}
          >
            {/* Aurora Gradient Border Layer */}
            <div className="aurora-border-layer" />

            {/* Input container */}
            <div className={`aurora-input-inner ${sizeClasses[inputSize]}`}>
              {icon && <span className="aurora-input-icon">{icon}</span>}
              <input
                className={`aurora-input-field ${className}`}
                onFocus={() => setIsFocused(true)}
                onBlur={() => setIsFocused(false)}
                {...rest}
              />
            </div>
          </div>

          {(helperText || error) && (
            <p className={`aurora-helper ${hasError ? 'aurora-error-text' : ''}`}>
              {error || helperText}
            </p>
          )}
        </div>
        );
        });

