                <span className="text-[10px] text-zinc-500 mt-1.5 font-semibold tracking-wider uppercase">{u.l}</span>
              </div>
              {i < 3 && <span className="text-xl text-violet-500 font-bold mt-[-12px]">:</span>}
            </React.Fragment>
          ))}
        </div>
        );
        });

