                             dx="10"
                             dy="20"
                             fill="#64ffda" 
                             fontSize="12" 
                             fontWeight="bold"
                             className="pointer-events-none drop-shadow-[0_0_5px_rgba(100,255,218,1)]"
                           >
                             {room.name}
                           </text>
                         )}
                       </motion.g>
                     )
                   })}
                </svg>
             </motion.div>
          </div>

        </div>
        );
        });

