            onClick={toggle}
            className={`morph-toggle-track ${checked ? 'on' : 'off'} ${sizeClass}`}
          >
            <span className="morph-toggle-thumb" />
          </button>
          {label && (
            <span className="text-sm font-medium text-white/70">{label}</span>
          )}
        </div>
        );
        });

