import React, { useRef, useState, useEffect } from "react";
import { PenTool, RotateCcw } from "lucide-react";
import { cn } from "@/lib/utils";

export interface LaserSignaturePadProps {
  onClear?: () => void;
    className?: string;
}

export const LaserSignaturePad = React.forwardRef<any, LaserSignaturePadProps>(({ className, onClear, ...props }, ref) => {
        const canvasRef = useRef<HTMLCanvasElement>(null);
        const [isDrawing, setIsDrawing] = useState(false);

        // Set up canvas context properties
        useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext("2d");
        if (!ctx) return;

        // Handle high DPI displays for crisp rendering
        const dpr = window.devicePixelRatio || 1;
        const rect = canvas.getBoundingClientRect();

        // Set actual size in memory (scaled to account for extra pixel density)
        canvas.width = rect.width * dpr;
        canvas.height = rect.height * dpr;

        // Normalize coordinate system to use css pixels
        ctx.scale(dpr, dpr);

        // Initial contextual laser styling
        ctx.lineCap = "round";
        ctx.lineJoin = "round";
        ctx.shadowBlur = 15;
        ctx.shadowColor = "#06b6d4"; // Cyan glow
        ctx.strokeStyle = "#ffffff"; // Core white
        // Base width varying slightly for pressure simulation if we wanted to
        }, []);

        const getPointerPos = (e: React.PointerEvent<HTMLCanvasElement>) => {
        const canvas = canvasRef.current;
        if (!canvas) return { x: 0, y: 0 };
        const rect = canvas.getBoundingClientRect();
        return {
           x: e.clientX - rect.left,
           y: e.clientY - rect.top
        };
        };

        const startDrawing = (e: React.PointerEvent<HTMLCanvasElement>) => {
        const ctx = canvasRef.current?.getContext("2d");
        if (!ctx) return;
        const { x, y } = getPointerPos(e);

        ctx.beginPath();
        ctx.moveTo(x, y);
        setIsDrawing(true);
        e.currentTarget.setPointerCapture(e.pointerId); // Support continuing out of bounds
        };

        const draw = (e: React.PointerEvent<HTMLCanvasElement>) => {
        if (!isDrawing) return;
        const ctx = canvasRef.current?.getContext("2d");
        if (!ctx) return;

        // Simulate varying pressure based on movement speed ideally, but simple fixed width for now
        ctx.lineWidth = e.pressure && e.pointerType !== "mouse" ? e.pressure * 5 : 3;

        const { x, y } = getPointerPos(e);
        ctx.lineTo(x, y);
        ctx.stroke();
        };

        const stopDrawing = (e: React.PointerEvent<HTMLCanvasElement>) => {
        setIsDrawing(false);
        e.currentTarget.releasePointerCapture(e.pointerId);
        };

        const handleClear = () => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext("2d");
        if (!ctx) return;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        if (onClear) onClear();
        };

        return (
        <div ref={ref} {...props} className={cn("w-full max-w-lg bg-zinc-950 border border-zinc-900 rounded-3xl p-6 shadow-2xl", className)}>
          <div className="flex items-center justify-between mb-4 px-2">
             <div className="flex items-center gap-2 text-zinc-400">
               <PenTool size={18} />
               <span className="font-medium text-sm">Sign Document</span>
             </div>
             <button 
               onClick={handleClear}
               className="text-zinc-600 hover:text-zinc-300 transition-colors flex flex-center"
               title="Clear Signature"
