          const currentCount = Math.floor(end * easeOutExpo(percentage));

          setCount(currentCount);

          if (progress < duration) {
            animationFrameId = requestAnimationFrame(animate);
          } else {
            setCount(end); // Ensure we end exactly at the target number
          }
        };

